function AdminPanel({ onClose }) {
  const [emails, setEmails] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    async function load() {
      try {
        const result = await window.storage.get("rr_signups");
        if (result && result.value) {
          setEmails(JSON.parse(result.value));
        }
      } catch (e) {
        setError("No sign-ups yet or storage unavailable.");
      }
      setLoading(false);
    }
    load();
  }, []);

  const handleClear = async () => {
    if (!confirm("Are you sure you want to clear all sign-ups?")) return;
    try {
      await window.storage.delete("rr_signups");
      setEmails([]);
    } catch (e) {
      setError("Could not clear data.");
    }
  };

  const handleExport = () => {
    const csv = "Email,Date\n" + emails.map(e => e.email + "," + e.date).join("\n");
    const blob = new Blob([csv], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "readers-realm-signups.csv";
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 1000,
      background: "rgba(0,0,0,0.85)", backdropFilter: "blur(6px)",
      display: "flex", alignItems: "center", justifyContent: "center", padding: 20
    }} onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{
        background: COLORS.card, borderRadius: 16, maxWidth: 600,
        width: "100%", maxHeight: "85vh", overflowY: "auto", padding: 32,
        border: "1px solid " + COLORS.accent + "55",
        boxShadow: "0 24px 80px rgba(0,0,0,0.6)"
      }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
          <div>
            <h2 style={{ fontFamily: FONT_DISPLAY, color: COLORS.accent, fontSize: 22, margin: 0 }}>
              Admin Panel
            </h2>
            <p style={{ fontFamily: FONT_BODY, color: COLORS.sage, fontSize: 11, marginTop: 4 }}>
              Email sign-ups from persistent storage
            </p>
          </div>
          <button onClick={onClose} style={{
            background: "none", border: "none", color: COLORS.sage,
            cursor: "pointer", fontSize: 24, lineHeight: 1
          }}>X</button>
        </div>

        <div style={{
          display: "flex", gap: 8, marginBottom: 16
        }}>
          <div style={{
            flex: 1, padding: "12px 16px", borderRadius: 8,
            background: COLORS.bg, border: "1px solid " + COLORS.teal + "44",
            textAlign: "center"
          }}>
            <div style={{ fontSize: 24, fontWeight: 700, color: COLORS.accent, fontFamily: FONT_DISPLAY }}>
              {emails.length}
            </div>
            <div style={{ fontSize: 10, color: COLORS.sage, fontFamily: FONT_BODY, marginTop: 2 }}>
              Total Sign-ups
            </div>
          </div>
          <button onClick={handleExport} disabled={emails.length === 0} style={{
            padding: "12px 16px", borderRadius: 8, background: COLORS.teal,
            border: "none", color: COLORS.cream, fontSize: 12,
            fontWeight: 700, cursor: emails.length ? "pointer" : "default",
            fontFamily: FONT_BODY, opacity: emails.length ? 1 : 0.4
          }}>
            Export CSV
          </button>
          <button onClick={handleClear} disabled={emails.length === 0} style={{
            padding: "12px 16px", borderRadius: 8, background: "transparent",
            border: "1px solid #8B3A3A88", color: "#8B3A3A", fontSize: 12,
            fontWeight: 700, cursor: emails.length ? "pointer" : "default",
            fontFamily: FONT_BODY, opacity: emails.length ? 1 : 0.4
          }}>
            Clear All
          </button>
        </div>

        {loading ? (
          <p style={{ color: COLORS.sage, fontSize: 13, fontFamily: FONT_BODY, textAlign: "center", padding: 20 }}>
            Loading...
          </p>
        ) : error && emails.length === 0 ? (
          <p style={{ color: COLORS.sage, fontSize: 13, fontFamily: FONT_BODY, textAlign: "center", padding: 20 }}>
            {error}
          </p>
        ) : emails.length === 0 ? (
          <p style={{ color: COLORS.sage, fontSize: 13, fontFamily: FONT_BODY, textAlign: "center", padding: 20 }}>
            No sign-ups yet. Emails will appear here when users sign up.
          </p>
        ) : (
          <div style={{ borderRadius: 8, overflow: "hidden", border: "1px solid " + COLORS.sage + "22" }}>
            <div style={{
              display: "grid", gridTemplateColumns: "1fr 40px 180px",
              padding: "10px 14px", background: COLORS.bg,
              fontSize: 10, fontWeight: 700, color: COLORS.accent,
              textTransform: "uppercase", letterSpacing: 1, fontFamily: FONT_BODY
            }}>
              <span>Email</span>
              <span>#</span>
              <span>Date</span>
            </div>
            {emails.map((entry, i) => (
              <div key={i} style={{
                display: "grid", gridTemplateColumns: "1fr 40px 180px",
                padding: "10px 14px",
                borderTop: "1px solid " + COLORS.sage + "15",
                fontSize: 12, color: COLORS.cream, fontFamily: FONT_BODY
              }}>
                <span style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                  {entry.email}
                </span>
                <span style={{ color: COLORS.sage }}>{i + 1}</span>
                <span style={{ color: COLORS.sage, fontSize: 11 }}>
                  {new Date(entry.date).toLocaleString()}
                </span>
              </div>
            ))}
          </div>
        )}

        <p style={{
          fontSize: 10, color: COLORS.sage, fontFamily: FONT_BODY,
          marginTop: 16, textAlign: "center", opacity: 0.6
        }}>
          Access this panel by clicking the logo 5 times quickly
        </p>
      </div>
    </div>
  );
}

export default function ReadersRealm() {
  const [search, setSearch] = useState("");
  const [sortBy, setSortBy] = useState("popular");
  const [genre, setGenre] = useState("all");
  const [selectedBook, setSelectedBook] = useState(null);
  const [showSignUp, setShowSignUp] = useState(false);
  const [showAbout, setShowAbout] = useState(false);
  const [showAdmin, setShowAdmin] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);
  const [showSurveyNudge, setShowSurveyNudge] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const booksOpenedRef = useRef(0);
  const surveyShownRef = useRef(false);
  const logoClicksRef = useRef([]);

  useEffect(() => {
    try {
      const seen = localStorage.getItem("rr_welcome_seen");
      if (!seen) {
        setShowWelcome(true);
        localStorage.setItem("rr_welcome_seen", "1");
      }
    } catch (e) {
      setShowWelcome(true);
    }
  }, []);
  const [incTropes, setIncTropes] = useState([]);
  const [incWarnings, setIncWarnings] = useState([]);
  const [incTags, setIncTags] = useState([]);
  const [excTropes, setExcTropes] = useState([]);
  const [excWarnings, setExcWarnings] = useState([]);
  const [excTags, setExcTags] = useState([]);
  const [seriesFilter, setSeriesFilter] = useState("all");
  const [language, setLanguage] = useState("all");
  const [minPages, setMinPages] = useState("");
  const [maxPages, setMaxPages] = useState("");
  const [contentRating, setContentRating] = useState([]);

  const clearAll = () => {
    setSearch(""); setSortBy("popular"); setGenre("all");
    setIncTropes([]); setIncWarnings([]); setIncTags([]);
    setExcTropes([]); setExcWarnings([]); setExcTags([]);
    setSeriesFilter("all"); setLanguage("all");
    setMinPages(""); setMaxPages(""); setContentRating([]);
  };

  const toggleCR = (r) => {
    setContentRating(contentRating.includes(r)
      ? contentRating.filter(c => c !== r)
      : [...contentRating, r]);
  };

  let filtered = BOOKS.filter(book => {
    if (search) {
      const s = search.toLowerCase();
      if (!book.title.toLowerCase().includes(s) && !book.author.toLowerCase().includes(s)) return false;
    }
    if (genre !== "all" && !book.genres.includes(genre)) return false;
    if (contentRating.length && !contentRating.includes(book.contentRating)) return false;
    if (seriesFilter !== "all" && book.seriesStatus !== seriesFilter) return false;
    if (language !== "all" && book.language !== language) return false;
    if (minPages && book.pages < parseInt(minPages)) return false;
    if (maxPages && book.pages > parseInt(maxPages)) return false;
    if (incTropes.length && !incTropes.every(t => book.tropes.includes(t))) return false;
    if (incWarnings.length && !incWarnings.every(w => book.warnings.includes(w))) return false;
    if (incTags.length && !incTags.every(t => book.tags.includes(t))) return false;
    if (excTropes.length && excTropes.some(t => book.tropes.includes(t))) return false;
    if (excWarnings.length && excWarnings.some(w => book.warnings.includes(w))) return false;
    if (excTags.length && excTags.some(t => book.tags.includes(t))) return false;
    return true;
  });

  filtered.sort((a, b) => {
    if (sortBy === "popular") return b.rating - a.rating;
    if (sortBy === "new") return b.year - a.year;
    if (sortBy === "title") return a.title.localeCompare(b.title);
    if (sortBy === "author") return a.author.localeCompare(b.author);
    return 0;
  });

  const selectStyle = {
    width: "100%", padding: "8px 12px", background: COLORS.bg,
    border: "1px solid " + COLORS.sage + "33", borderRadius: 6,
    color: COLORS.cream, fontSize: 12, fontFamily: FONT_BODY
  };

  return (
    <div style={{ minHeight: "100vh", background: COLORS.bg, fontFamily: FONT_BODY }}>
      <style>{
        "@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,600;0,700;0,800;1,400;1,700&family=Libre+Baskerville:ital,wght@0,400;0,700;1,400&display=swap');" +
        "* { box-sizing: border-box; margin: 0; padding: 0; }" +
        "::-webkit-scrollbar { width: 5px; }" +
        "::-webkit-scrollbar-track { background: transparent; }" +
        "::-webkit-scrollbar-thumb { background: " + COLORS.accent + "33; border-radius: 3px; }" +
        "select option { background: " + COLORS.bg + "; color: " + COLORS.cream + "; }" +
        ".rr-sidebar { transition: transform 0.3s ease; }" +
        "@media (max-width: 700px) {" +
          ".rr-header-inner { flex-wrap: wrap; gap: 8px !important; padding: 8px 14px !important; }" +
          ".rr-header-actions { margin-left: auto !important; gap: 6px !important; }" +
          ".rr-about-btn { display: none !important; }" +
          ".rr-search-wrap { width: 100% !important; max-width: 100% !important; }" +
          ".rr-hero { padding: 28px 16px 24px !important; }" +
          ".rr-main-layout { flex-direction: column !important; }" +
          ".rr-sidebar { position: fixed !important; top: 0 !important; left: 0 !important; width: 285px !important; height: 100vh !important; z-index: 200 !important; background: " + COLORS.card + " !important; border-right: 1px solid " + COLORS.accent + "33 !important; padding-top: 16px !important; transform: translateX(-100%); }" +
          ".rr-sidebar.open { transform: translateX(0) !important; }" +
          ".rr-sidebar-overlay { display: block !important; }" +
          ".rr-filter-fab { display: flex !important; }" +
          ".rr-main-content { padding: 16px 14px !important; }" +
          ".rr-book-detail-inner { flex-direction: column !important; align-items: center !important; }" +
          ".rr-book-detail-cover { width: 130px !important; min-width: unset !important; }" +
          ".rr-sidebar-close { display: block !important; }" +
        "}" +
        ".rr-sidebar-overlay { display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.55); z-index: 199; }" +
        ".rr-filter-fab { display: none; position: fixed; bottom: 22px; left: 50%; transform: translateX(-50%); z-index: 100; align-items: center; gap: 8px; background: " + COLORS.accent + "; color: " + COLORS.card + "; border: none; padding: 12px 28px; border-radius: 30px; font-size: 14px; font-weight: 700; cursor: pointer; font-family: inherit; box-shadow: 0 4px 20px rgba(0,0,0,0.4); white-space: nowrap; }"
      }</style>

      {/* HEADER */}
      <header style={{
        background: COLORS.card,
        borderBottom: "1px solid " + COLORS.accent + "18",
        position: "sticky", top: 0, zIndex: 50
      }}>
        <div
          className="rr-header-inner"
          style={{
          maxWidth: 1440, margin: "0 auto", padding: "10px 28px",
          display: "flex", alignItems: "center", gap: 20
        }}>
          <div
            style={{ display: "flex", alignItems: "center", gap: 10, cursor: "pointer", flexShrink: 0 }}
            onClick={() => {
              const now = Date.now();
              logoClicksRef.current.push(now);
              logoClicksRef.current = logoClicksRef.current.filter(t => now - t < 2000);
              if (logoClicksRef.current.length >= 5) {
                logoClicksRef.current = [];
                setShowAdmin(true);
                return;
              }
              clearAll(); setSelectedBook(null);
            }}
          >
            <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke={COLORS.cream} strokeWidth="1.5">
              <path d="M4 19.5A2.5 2.5 0 016.5 17H20" />
              <path d="M6.5 2H20v20H6.5A2.5 2.5 0 014 19.5v-15A2.5 2.5 0 016.5 2z" />
            </svg>
            <span style={{
              fontFamily: FONT_DISPLAY, fontSize: 18, fontWeight: 700,
              color: COLORS.accent, fontStyle: "italic"
            }}>
              {"Readers' Realm"}
            </span>
          </div>

          <div className="rr-search-wrap" style={{ flex: 1, maxWidth: 480 }}>
            <div style={{
              display: "flex", alignItems: "center", background: COLORS.bg,
              borderRadius: 24, padding: "0 16px",
              border: "1px solid " + COLORS.sage + "22"
            }}>
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={COLORS.sage} strokeWidth="2">
                <circle cx="11" cy="11" r="8" />
                <line x1="21" y1="21" x2="16.65" y2="16.65" />
              </svg>
              <input
                value={search}
                onChange={e => setSearch(e.target.value)}
                placeholder="Search title or author..."
                style={{
                  flex: 1, padding: "9px 12px", background: "transparent",
                  border: "none", color: COLORS.cream, fontSize: 13,
                  outline: "none", fontFamily: FONT_BODY
                }}
              />
            </div>
          </div>

          <div className="rr-header-actions" style={{ display: "flex", gap: 10, alignItems: "center", marginLeft: "auto" }}>
            <a
              className="rr-survey-btn"
              href="https://forms.gle/kTh3X1YxN6TTYcjn9"
              target="_blank"
              rel="noopener noreferrer"
              style={{
                display: "inline-flex", alignItems: "center", gap: 6,
                background: "linear-gradient(135deg, " + COLORS.teal + ", #2a7a6e)",
                border: "none",
                color: COLORS.cream, padding: "8px 16px", borderRadius: 6,
                cursor: "pointer", fontSize: 13, fontFamily: FONT_BODY,
                textDecoration: "none", fontWeight: 700,
                boxShadow: "0 0 12px " + COLORS.teal + "66",
                letterSpacing: 0.3
              }}
              onMouseEnter={e => {
                e.currentTarget.style.boxShadow = "0 0 20px " + COLORS.teal + "99";
                e.currentTarget.style.transform = "translateY(-1px)";
              }}
              onMouseLeave={e => {
                e.currentTarget.style.boxShadow = "0 0 12px " + COLORS.teal + "66";
                e.currentTarget.style.transform = "translateY(0)";
              }}
            >
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2">
                <path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/>
                <polyline points="14 2 14 8 20 8"/>
                <line x1="16" y1="13" x2="8" y2="13"/>
                <line x1="16" y1="17" x2="8" y2="17"/>
                <polyline points="10 9 9 9 8 9"/>
              </svg>
              Survey
            </a>
            <button onClick={() => setShowSignUp(true)} style={{
              background: COLORS.accent, border: "none", color: COLORS.card,
              padding: "8px 22px", borderRadius: 6, cursor: "pointer",
              fontSize: 13, fontWeight: 700, fontFamily: FONT_BODY
            }}>Sign Up</button>
            <button
              className="rr-about-btn"
              onClick={() => setShowAbout(true)}
              style={{
                background: "none", border: "1px solid " + COLORS.cream + "33",
                color: COLORS.cream, padding: "7px 16px", borderRadius: 6,
                cursor: "pointer", fontSize: 13, fontFamily: FONT_BODY,
                fontWeight: 600, letterSpacing: 0.3, transition: "border-color 0.2s, color 0.2s"
              }}
              onMouseEnter={e => {
                e.currentTarget.style.borderColor = COLORS.cream + "88";
                e.currentTarget.style.color = COLORS.cream;
              }}
              onMouseLeave={e => {
                e.currentTarget.style.borderColor = COLORS.cream + "33";
                e.currentTarget.style.color = COLORS.cream;
              }}
            >About</button>
          </div>
        </div>
      </header>

      {/* HERO */}
      <div className="rr-hero" style={{
        background: "linear-gradient(135deg, " + COLORS.brown + "cc 0%, " + COLORS.card + " 40%, " + COLORS.teal + "88 100%)",
        padding: "52px 28px 48px", textAlign: "center"
      }}>
        <div style={{
          fontSize: 10, color: COLORS.accent, textTransform: "uppercase",
          letterSpacing: 4, marginBottom: 12, fontFamily: FONT_BODY, fontWeight: 700
        }}>
          Where Every Book Finds Its Reader
        </div>
        <h1 style={{
          fontFamily: FONT_DISPLAY, fontSize: "clamp(30px, 5vw, 52px)",
          color: COLORS.cream, fontWeight: 700, margin: "0 0 14px", lineHeight: 1.15
        }}>
          Discover Books on{" "}
          <span style={{ fontStyle: "italic", color: COLORS.accent }}>Your Terms</span>
        </h1>
        <p style={{
          fontSize: "clamp(13px, 1.8vw, 16px)", color: COLORS.cream,
          opacity: 0.6, maxWidth: 600, margin: "0 auto", lineHeight: 1.6, fontFamily: FONT_BODY
        }}>
          Filter by tropes, content warnings, ratings, and more. Find exactly what you are ready to read.
        </p>
      </div>

      {/* MAIN */}
      <div className="rr-main-layout" style={{ maxWidth: 1440, margin: "0 auto", display: "flex", minHeight: "80vh" }}>

        {/* SIDEBAR OVERLAY */}
        <div className="rr-sidebar-overlay" onClick={() => setSidebarOpen(false)} />

        {/* SIDEBAR */}
        <aside className={"rr-sidebar" + (sidebarOpen ? " open" : "")} style={{
          width: 260, flexShrink: 0, padding: "20px 20px 40px",
          borderRight: "1px solid " + COLORS.sage + "15",
          position: "sticky", top: 52, height: "calc(100vh - 52px)", overflowY: "auto"
        }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
            <span style={{
              fontSize: 12, fontWeight: 700, color: COLORS.cream,
              textTransform: "uppercase", letterSpacing: 2, fontFamily: FONT_BODY
            }}>Filters</span>
            <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
              <button onClick={clearAll} style={{
                background: "none", border: "none", color: COLORS.accent,
                fontSize: 11, cursor: "pointer", fontFamily: FONT_BODY
              }}>Clear All</button>
              <button onClick={() => setSidebarOpen(false)} style={{
                background: "none", border: "none", color: COLORS.sage,
                fontSize: 20, cursor: "pointer", lineHeight: 1,
                display: "none"
              }} className="rr-sidebar-close">✕</button>
            </div>
          </div>

          <FilterSection title="Sort By">
            <select value={sortBy} onChange={e => setSortBy(e.target.value)} style={selectStyle}>
              {SORTS.map(o => <option key={o.v} value={o.v}>{o.l}</option>)}
            </select>
          </FilterSection>

          <FilterSection title="Genre">
            <select value={genre} onChange={e => setGenre(e.target.value)} style={selectStyle}>
              <option value="all">Select genres...</option>
              {ALL_GENRES.map(g => <option key={g} value={g}>{g}</option>)}
            </select>
          </FilterSection>

          <FilterSection title="Content Rating">
            {CRATS.map(r => (
              <label key={r} style={{
                display: "flex", alignItems: "center", gap: 8,
                padding: "4px 0", cursor: "pointer", fontSize: 12,
                color: COLORS.cream, fontFamily: FONT_BODY
              }}>
                <input
                  type="checkbox"
                  checked={contentRating.includes(r)}
                  onChange={() => toggleCR(r)}
                  style={{ accentColor: COLORS.accent }}
                />
                {r}
              </label>
            ))}
          </FilterSection>

          <FilterSection title="Series Status">
            <select value={seriesFilter} onChange={e => setSeriesFilter(e.target.value)} style={selectStyle}>
              <option value="all">All</option>
              <option value="completed">Completed</option>
              <option value="not completed">Ongoing</option>
              <option value="standalone">Standalone</option>
            </select>
          </FilterSection>

          <FilterSection title="Language">
            <select value={language} onChange={e => setLanguage(e.target.value)} style={selectStyle}>
              <option value="all">All Languages</option>
              {ALL_LANGS.map(l => <option key={l} value={l}>{l}</option>)}
            </select>
          </FilterSection>

          <FilterSection title="Page Count">
            <div style={{ display: "flex", gap: 8 }}>
              <input type="number" value={minPages} onChange={e => setMinPages(e.target.value)}
                placeholder="Min" style={{ ...selectStyle, width: "50%" }} />
              <input type="number" value={maxPages} onChange={e => setMaxPages(e.target.value)}
                placeholder="Max" style={{ ...selectStyle, width: "50%" }} />
            </div>
          </FilterSection>

          <FilterSection title="Include">
            <div style={{ marginBottom: 2 }}>
              <label style={{ fontSize: 9, color: COLORS.sage, textTransform: "uppercase", letterSpacing: 1 }}>Warnings</label>
            </div>
            <MultiSelect label="Warnings..." options={ALL_WARNINGS} selected={incWarnings} onChange={setIncWarnings} />
            <div style={{ marginBottom: 2, marginTop: 6 }}>
              <label style={{ fontSize: 9, color: COLORS.sage, textTransform: "uppercase", letterSpacing: 1 }}>Tropes</label>
            </div>
            <MultiSelect label="Tropes..." options={ALL_TROPES} selected={incTropes} onChange={setIncTropes} />
            <div style={{ marginBottom: 2, marginTop: 6 }}>
              <label style={{ fontSize: 9, color: COLORS.sage, textTransform: "uppercase", letterSpacing: 1 }}>Tags</label>
            </div>
            <MultiSelect label="Tags..." options={ALL_TAGS} selected={incTags} onChange={setIncTags} />
          </FilterSection>

          <FilterSection title="Exclude" defaultOpen={false}>
            <div style={{ marginBottom: 2 }}>
              <label style={{ fontSize: 9, color: COLORS.sage, textTransform: "uppercase", letterSpacing: 1 }}>Warnings</label>
            </div>
            <MultiSelect label="Warnings..." options={ALL_WARNINGS} selected={excWarnings} onChange={setExcWarnings} />
            <div style={{ marginBottom: 2, marginTop: 6 }}>
              <label style={{ fontSize: 9, color: COLORS.sage, textTransform: "uppercase", letterSpacing: 1 }}>Tropes</label>
            </div>
            <MultiSelect label="Tropes..." options={ALL_TROPES} selected={excTropes} onChange={setExcTropes} />
            <div style={{ marginBottom: 2, marginTop: 6 }}>
              <label style={{ fontSize: 9, color: COLORS.sage, textTransform: "uppercase", letterSpacing: 1 }}>Tags</label>
            </div>
            <MultiSelect label="Tags..." options={ALL_TAGS} selected={excTags} onChange={setExcTags} />
          </FilterSection>
        </aside>

        {/* BOOK GRID */}
        <main className="rr-main-content" style={{ flex: 1, padding: "24px 28px" }}>
          <div style={{
            display: "flex", justifyContent: "space-between",
            alignItems: "baseline", marginBottom: 20
          }}>
            <div style={{ fontFamily: FONT_BODY, color: COLORS.sage, fontSize: 14 }}>
              <span style={{ color: COLORS.accent, fontWeight: 700, fontSize: 16 }}>{filtered.length}</span>
              {" books found"}
            </div>
            <div style={{ fontSize: 12, color: COLORS.sage, fontFamily: FONT_BODY, opacity: 0.6 }}>
              Click any cover to see full details
            </div>
          </div>

          {filtered.length === 0 ? (
            <div style={{ textAlign: "center", padding: "80px 20px", color: COLORS.cream, opacity: 0.4 }}>
              <p style={{ fontFamily: FONT_DISPLAY, fontSize: 18, marginBottom: 8 }}>No books match your filters</p>
              <p style={{ fontSize: 13 }}>Try adjusting your filters or clearing them.</p>
            </div>
          ) : (
            <div style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fill, minmax(175px, 1fr))",
              gap: 24
            }}>
              {filtered.map(book => (
                <BookCard key={book.id} book={book} onClick={(b) => {
                  setSelectedBook(b);
                  if (!surveyShownRef.current) {
                    booksOpenedRef.current += 1;
                    if (booksOpenedRef.current >= 2) {
                      surveyShownRef.current = true;
                      setTimeout(() => setShowSurveyNudge(true), 600);
                    }
                  }
                }} />
              ))}
            </div>
          )}
        </main>
      </div>

      {/* MOBILE FILTER FAB */}
      <button className="rr-filter-fab" onClick={() => setSidebarOpen(true)}>
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
          <line x1="4" y1="6" x2="20" y2="6"/><line x1="8" y1="12" x2="16" y2="12"/><line x1="11" y1="18" x2="13" y2="18"/>
        </svg>
        Filters
      </button>

      {/* FOOTER */}
      <footer style={{
        borderTop: "1px solid " + COLORS.sage + "15",
        padding: "28px 24px", textAlign: "center", marginTop: 20
      }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 8, marginBottom: 8 }}>
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={COLORS.cream} strokeWidth="1.5">
            <path d="M4 19.5A2.5 2.5 0 016.5 17H20" />
            <path d="M6.5 2H20v20H6.5A2.5 2.5 0 014 19.5v-15A2.5 2.5 0 016.5 2z" />
          </svg>
          <span style={{ fontFamily: FONT_DISPLAY, color: COLORS.accent, fontSize: 13, fontWeight: 700, fontStyle: "italic" }}>
            {"Readers' Realm"}
          </span>
        </div>
        <p style={{ color: COLORS.sage, fontSize: 10, fontFamily: FONT_BODY }}>
          Where Every Book Finds Its Reader
        </p>
        <p style={{ color: COLORS.sage, fontSize: 9, marginTop: 6, fontFamily: FONT_BODY }}>
          {"© 2026 Readers' Realm - MVP Demo"}
        </p>
      </footer>

      {selectedBook && <BookDetail book={selectedBook} onClose={() => setSelectedBook(null)} />}
      {showSignUp && <SignUpModal onClose={() => setShowSignUp(false)} />}
      {showAbout && <AboutModal onClose={() => setShowAbout(false)} />}
      {showAdmin && <AdminPanel onClose={() => setShowAdmin(false)} />}
      {showWelcome && <WelcomeModal onClose={() => setShowWelcome(false)} />}
      {showSurveyNudge && <SurveyNudge onClose={() => setShowSurveyNudge(false)} />}
    </div>
  );
}
